<template>
    <div class="table">
        <div class="container">
            <div class="handle-box">
                <el-input v-model="select_word" placeholder="请输入标题" class="handle-input"></el-input>
                <br><br>
                <el-button type="danger" style="font-size: 18px;" @click="delAll"> 批量删除</el-button>
                <el-button type="success" style="font-size: 18px;" @click="centerDialogVisible = true"> 添加公告</el-button>
            </div>
        </div>

        <el-table ref="multipleTable" border style="width:100%" height="680px" :data="data" @selection-change="handleSelectionChange">
            <el-table-column type="selection" width="40"></el-table-column>
            <el-table-column prop="title" label="标题" width="220" align="center"></el-table-column>
            <el-table-column label="内容" align="left">
                <template slot-scope="scope">
                    <div style="line-height: 1.6; white-space: pre-line;">
                        {{ scope.row.content }}
                    </div>
                </template>
            </el-table-column>
            <el-table-column label="上下架" width="120" align="center">
                <template slot-scope="scope">
                    <el-switch
                        v-model="scope.row.status"
                        :active-value="1"
                        :inactive-value="0"
                        @change="toggleStatus(scope.row)"
                    ></el-switch>
                </template>
            </el-table-column>
            <el-table-column label="操作" width="220" align="center">
                <template slot-scope="scope">
                    <el-button style="font-size: 16px;" type="success" @click="handleEdit(scope.row)"> 编辑</el-button>
                    <el-button style="font-size: 16px;" type="danger" @click="handleDelete(scope.row.id)"> 删除</el-button>
                </template>
            </el-table-column>
        </el-table>

        <div class="pagination">
            <el-pagination
                background
                layout="total,prev,pager,next"
                :current-page="currentPage"
                :page-size="pageSize"
                :total="tableData.length"
                @current-change="handleCurrentChange"
            >
            </el-pagination>
        </div>

        <el-dialog title="添加公告" :visible.sync="centerDialogVisible" width="520px" center>
            <el-form :model="registerForm" ref="registerForm" label-width="90px">
                <el-form-item prop="title" label="标题" size="mini">
                    <el-input v-model="registerForm.title" placeholder="请输入标题"></el-input>
                </el-form-item>
                <el-form-item prop="content" label="内容" size="mini">
                    <el-input type="textarea" :rows="5" v-model="registerForm.content" placeholder="请输入公告内容"></el-input>
                </el-form-item>
                <el-form-item prop="status" label="上下架" size="mini">
                    <el-select v-model="registerForm.status" placeholder="请选择">
                        <el-option key="1" label="上架" :value="1"></el-option>
                        <el-option key="0" label="下架" :value="0"></el-option>
                    </el-select>
                </el-form-item>
            </el-form>
            <span slot="footer">
                <el-button size="mini" @click="centerDialogVisible = false"> 取消</el-button>
                <el-button size="mini" @click="addNotice" type="primary"> 保存</el-button>
            </span>
        </el-dialog>

        <el-dialog title="编辑公告" :visible.sync="editVisible" width="520px" center>
            <el-form :model="form" ref="form" label-width="90px">
                <el-form-item prop="title" label="标题" size="mini">
                    <el-input v-model="form.title" placeholder="请输入标题"></el-input>
                </el-form-item>
                <el-form-item prop="content" label="内容" size="mini">
                    <el-input type="textarea" :rows="5" v-model="form.content" placeholder="请输入公告内容"></el-input>
                </el-form-item>
                <el-form-item prop="status" label="上下架" size="mini">
                    <el-select v-model="form.status" placeholder="请选择">
                        <el-option key="1" label="上架" :value="1"></el-option>
                        <el-option key="0" label="下架" :value="0"></el-option>
                    </el-select>
                </el-form-item>
            </el-form>
            <span slot="footer">
                <el-button size="mini" @click="editVisible = false"> 取消</el-button>
                <el-button size="mini" @click="editSave" type="primary"> 保存</el-button>
            </span>
        </el-dialog>

        <el-dialog title="删除公告" :visible.sync="delVisible" width="300px" center>
            <div align="center">删除后不可恢复，确认删除？</div>
            <span slot="footer">
                <el-button size="mini" @click="delVisible = false"> 取消</el-button>
                <el-button size="mini" @click="deleteRow" type="primary"> 确认</el-button>
            </span>
        </el-dialog>
    </div>
</template>

<script>
import { getAllNotice, setNotice, updateNotice, delNotice, updateNoticeStatus } from "../api/index";
import { mixin } from "../mixins/index";

export default {
    mixins: [mixin],
    data(){
        return{
            centerDialogVisible: false,
            editVisible: false,
            delVisible: false,
            registerForm:{
                title: "",
                content: "",
                link: "",
                sort: 0,
                status: 1,
            },
            form:{
                id: "",
                title: "",
                content: "",
                link: "",
                sort: 0,
                status: 1,
            },
            tableData: [],
            tempData: [],
            select_word: "",
            pageSize: 5,
            currentPage: 1,
            idx: -1,
            multipleSelection: [],
        }
    },
    computed:{
        data(){
            return this.tableData.slice((this.currentPage - 1) * this.pageSize,this.currentPage * this.pageSize)
        }
    },
    watch:{
        select_word: function(){
            if(this.select_word == ''){
                this.tableData = this.tempData;
            }else{
                this.tableData = [];
                for(let item of this.tempData){
                    if((item.title || "").includes(this.select_word)){
                        this.tableData.push(item);
                    }
                }
            }
        },
        centerDialogVisible: function(val){
            if (val) {
                this.resetRegisterForm();
            }
        }
    },
    created(){
        this.getData();
    },
    methods:{
        resetRegisterForm(){
            if (this.$refs && this.$refs.registerForm && this.$refs.registerForm.resetFields) {
                this.$refs.registerForm.resetFields();
            }
            this.registerForm = {
                title: "",
                content: "",
                link: "",
                sort: 0,
                status: 1,
            };
        },
        handleCurrentChange(val){
            this.currentPage = val;
        },
        getData(){
            this.tempData = [];
            this.tableData = [];
            getAllNotice().then(res => {
                let arr = [];
                if (Array.isArray(res)) arr = res;
                else if (res && Array.isArray(res.data)) arr = res.data;
                else if (res && res.data && Array.isArray(res.data.data)) arr = res.data.data;
                else if (res && res.data && Array.isArray(res.data.list)) arr = res.data.list;
                else if (res && Array.isArray(res.list)) arr = res.list;

                const normalized = (arr || []).map((it) => {
                    const item = it || {};
                    return {
                        ...item,
                        title: item.title || "",
                        content: item.content || "",
                        sort: item.sort || 0,
                        status: item.status !== undefined ? item.status : (item.enabled ? 1 : 0),
                    };
                });

                this.tempData = normalized;
                this.tableData = normalized;
                this.currentPage = 1;
            })
        },
        addNotice(){
            const params = {
                title: this.registerForm.title,
                content: this.registerForm.content,
                link: this.registerForm.link,
                sort: this.registerForm.sort || 0,
                status: this.registerForm.status !== undefined ? this.registerForm.status : 1
            };
            setNotice(params)
            .then(res => {
                if(res.code == 1 || res.success){
                    this.getData();
                    this.notify("添加成功", "success");
                    this.resetRegisterForm();
                }else{
                    this.notify(res.msg || "添加失败", "error");
                }
            })
            .catch(err => {
                console.log(err);
            });
            this.centerDialogVisible = false;
        },
        handleEdit(row){
            this.editVisible = true;
            this.form = {
                id: row.id,
                title: row.title,
                content: row.content,
                link: row.link || "",
                sort: row.sort || 0,
                status: row.status
            }
        },
        editSave(){
            const params = {
                id: this.form.id,
                title: this.form.title,
                content: this.form.content,
                link: this.form.link,
                sort: this.form.sort,
                status: this.form.status
            };
            updateNotice(params)
            .then(res => {
                if(res.code == 1 || res.success){
                    this.getData();
                    this.notify("更新成功", "success");
                }else{
                    this.notify(res.msg || "更新失败", "error");
                }
            })
            .catch(err => {
                console.log(err);
            });
            this.editVisible = false;
        },
        toggleStatus(row){
            if (!row || row.id === undefined) return;
            const params = { id: row.id, status: row.status };
            updateNoticeStatus(params)
            .then(res => {
                if(res.code == 1 || res.success){
                    this.notify("状态已更新", "success");
                }else{
                    this.notify("状态更新失败", "error");
                }
            })
            .catch(err => {
                console.log(err);
            });
        },
        deleteRow(){
            delNotice(this.idx)
            .then(res => {
                if(res){
                    this.getData();
                    this.notify("删除成功", "success");
                }else{
                    this.notify("删除失败", "error");
                }
            })
            .catch(err => {
                console.log(err);
            });
            this.delVisible = false;
        }
    }
}
</script>

<style scoped>
    .handle-box{
        margin-bottom: 20px;
        padding: 16px 18px;
        background: linear-gradient(135deg, rgba(59, 130, 246, 0.08), rgba(255, 255, 255, 0.95));
        border: 1px solid rgba(148, 163, 184, 0.25);
        border-radius: 14px;
        box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);
    }
    .handle-input{
        width: 320px;
        display: inline-block;
    }
    .pagination{
        display: flex;
        justify-content: center;
        margin-top: 16px;
    }
</style>



